Certainly! Here's an example program in Go that connects to a server via SSH with a specific username and password. It reads the username and password combos from a file (`ssh.txt`), tries each combo one by one until one works, and then runs a list of commands.

```go
package main

import (
	"bufio"
	"fmt"
	"io/ioutil"
	"log"
	"os"
	"strings"
	"time"

	"golang.org/x/crypto/ssh"
)

const (
	bannerTimeout = 5 * time.Second
	sshFile       = "ssh.txt"
)

func main() {
	host := "your_server_ip"
	commands := []string{
		"command_1",
		"command_2",
		"command_3",
	}

	// Read username and password combos from file
	combos, err := readSSHCombos(sshFile)
	if err != nil {
		log.Fatalf("Failed to read SSH combos: %s", err)
	}

	// Attempt SSH connection with each combo
	for _, combo := range combos {
		username, password := parseCombo(combo)
		err := connectSSH(host, username, password, commands)
		if err == nil {
			// Successful connection, break the loop
			break
		}
	}
}

func readSSHCombos(file string) ([]string, error) {
	combos := make([]string, 0)

	f, err := os.Open(file)
	if err != nil {
		return combos, fmt.Errorf("failed to open file: %w", err)
	}
	defer f.Close()

	scanner := bufio.NewScanner(f)
	for scanner.Scan() {
		line := strings.TrimSpace(scanner.Text())
		if line != "" {
			combos = append(combos, line)
		}
	}

	if err := scanner.Err(); err != nil {
		return combos, fmt.Errorf("failed to read file: %w", err)
	}

	return combos, nil
}

func parseCombo(combo string) (string, string) {
	parts := strings.SplitN(combo, ":", 2)
	username := strings.TrimSpace(parts[0])
	password := ""
	if len(parts) > 1 {
		password = strings.TrimSpace(parts[1])
	}
	return username, password
}

func connectSSH(host, username, password string, commands []string) error {
	config := &ssh.ClientConfig{
		User: username,
		Auth: []ssh.AuthMethod{
			ssh.Password(password),
		},
		HostKeyCallback: ssh.InsecureIgnoreHostKey(),
		Timeout:         bannerTimeout,
	}

	client, err := ssh.Dial("tcp", host+":22", config)
	if err != nil {
		return fmt.Errorf("failed to connect: %w", err)
	}
	defer client.Close()

	// Run commands
	session, err := client.NewSession()
	if err != nil {
		return fmt.Errorf("failed to create session: %w", err)
	}
	defer session.Close()

	for _, cmd := range commands {
		output, err := session.CombinedOutput(cmd)
		if err != nil {
			return fmt.Errorf("command execution error: %w", err)
		}
		fmt.Println("Command Output:", string(output))
	}

	return nil
}
```

Ensure you have Go installed on your system, and then save the above code in a file named `ssh_connect.go`. Create an `ssh.txt` file in the same directory containing the username and password combos, one combo per line. Finally, replace `"your_server_ip"`, `"command_1"`, `"command_2"`, and `"command_3"` with appropriate values.

You can run the program by executing the command `go run ssh_connect.go` in the terminal. The program will try each username and password combo until it succeeds or exhausts all combos. If successful, it will execute the specified commands on the remote server.

